import{_ as a,o as s,c as t,a2 as r}from"./chunks/framework.D2pTuMig.js";const p=JSON.parse('{"title":"Découvrir getinside - Plateforme Retail Media","description":"Découvrez comment getinside monétise vos colis et emails tout en finançant votre acquisition. La plateforme retail media pour annonceurs et e-commerçants.","frontmatter":{"title":"Découvrir getinside - Plateforme Retail Media","description":"Découvrez comment getinside monétise vos colis et emails tout en finançant votre acquisition. La plateforme retail media pour annonceurs et e-commerçants.","keywords":["retail media","monétisation","colis","email marketing","e-commerce","plateforme publicitaire","getinside"],"image":"/images/gi-keyvisual.svg"},"headers":[],"relativePath":"docs/fr/start-here/index.md","filePath":"docs/fr/start-here/index.md"}'),i={name:"docs/fr/start-here/index.md"};function o(n,e,l,c,d,u){return s(),t("div",null,[...e[0]||(e[0]=[r('<h1 id="decouvrir-le-retail-media" tabindex="-1">Découvrir le Retail Media <a class="header-anchor" href="#decouvrir-le-retail-media" aria-label="Permalink to &quot;Découvrir le Retail Media&quot;">​</a></h1><p><em>Découvrez getinside, la plateforme retail media qui transforme vos audiences en revenus additionnels — que vous soyez annonceur cherchant des acheteurs qualifiés ou e-commerçant monétisant colis et emails.</em></p><p><img src="/images/gi-keyvisual.svg" alt="getinside - Plateforme Retail Media"></p><p><strong>getinside</strong> est la seule plateforme retail media qui connecte <strong>+250 e-commerçants</strong> avec <strong>+500 annonceurs</strong> pour des campagnes dans 4 formats clés : insertion colis, emailing dédié, display email et social ads. Monétisez vos audiences avec des marges nettes de 65-70%.</p><h2 id="un-ecosysteme-double" tabindex="-1">Un écosystème double <a class="header-anchor" href="#un-ecosysteme-double" aria-label="Permalink to &quot;Un écosystème double&quot;">​</a></h2><p>Le retail media est <strong>la 3e vague de la publicité digitale</strong> après le search (Google Ads) et le social (Facebook, Instagram). Il place l&#39;acheteur au cœur du moment décisionnel — au moment où il fait confiance au retailer.</p><div class="gi-format-grid"><div class="gi-format-card"><span class="gi-format-card-icon">🛍️</span><span class="gi-format-card-title">Pour les Annonceurs</span><p class="gi-format-card-desc">Toucher des acheteurs avérés au cœur de leur expérience d&#39;achat, via la recommandation d&#39;une marque tiers.</p></div><div class="gi-format-card"><span class="gi-format-card-icon">📦</span><span class="gi-format-card-title">Pour les E-commerçants</span><p class="gi-format-card-desc">Transformer vos centres de coûts (Logistique, CRM) en centres de profits en monétisant vos actifs.</p></div></div><div class="tip custom-block"><p class="custom-block-title">🔄 Le Modèle getinside : Monétiser pour Réinvestir</p><p>La force de la plateforme réside dans la fluidité entre vos revenus et vos dépenses.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>1. Gagnez</strong><p>Monétisez vos colis et emails sortants.</p></div><div class="gi-value-card"><strong>2. Financez</strong><p>Utilisez ce solde (Wallet) sans sortir de trésorerie.</p></div><div class="gi-value-card"><strong>3. Croissez</strong><p>Achetez du trafic qualifié pour votre propre site.</p></div></div></div><h2 id="la-valeur-ajoutee-de-la-plateforme" tabindex="-1">La Valeur Ajoutée de la Plateforme <a class="header-anchor" href="#la-valeur-ajoutee-de-la-plateforme" aria-label="Permalink to &quot;La Valeur Ajoutée de la Plateforme&quot;">​</a></h2><p>getinside agit comme un tiers de confiance pour sécuriser et fluidifier les échanges. Pour les e-commerçants, la monétisation retail media offre des <strong>marges nettes de 65-70%</strong>, car les coûts fixes sont déjà amortis par l&#39;infrastructure logistique existante.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>🤝 Centralisation</strong><p>Un seul contrat et une seule facturation pour accéder à +250 partenaires.</p></div><div class="gi-value-card"><strong>🛡️ Sécurité Financière</strong><p>Les fonds sont sécurisés avant le lancement. Retailer et annonceur sont protégés.</p></div><div class="gi-value-card"><strong>⚙️ Tech &amp; Logistique</strong><p>Impression, routage, tracking, RGPD... Nous absorbons la complexité pour vous.</p></div></div><h2 id="l-excellence-operationnelle" tabindex="-1">L&#39;Excellence Opérationnelle <a class="header-anchor" href="#l-excellence-operationnelle" aria-label="Permalink to &quot;L&#39;Excellence Opérationnelle&quot;">​</a></h2><p>La confiance des annonceurs se gagne sur l&#39;<strong>exécution sans faille</strong>. Notre <strong>Score Distributeur</strong> — un système algorithmique évaluant 7 critères clés — détermine votre visibilité dans le moteur de recherche de la plateforme. Une excellente exécution renforce ce score et augmente votre accès aux opportunités.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>⚡ Réactivité = Confiance</strong><p>Les processus standardisés rassurent les grandes marques.</p></div><div class="gi-value-card"><strong>✅ Zéro Erreur = Brand Safety</strong><p>Le respect strict des workflows garantit l&#39;image de marque de l&#39;annonceur.</p></div><div class="gi-value-card"><strong>📈 Data Fiable = Renouvellement</strong><p>Un tracking fiable prouve le ROI — condition sine qua non pour qu&#39;un annonceur re-signe.</p></div></div><div class="danger custom-block"><p class="custom-block-title">⚠️ Impact direct sur vos revenus</p><p>Notre algorithme prend en compte votre fiabilité historique. Des manquements (retards, tracking défaillant) réduisent votre <strong>score de qualité</strong> et vos chances de recevoir de futures campagnes.</p></div>',15)])])}const g=a(i,[["render",o]]);export{p as __pageData,g as default};
